function initializeHeroCarousel(){document.querySelectorAll(".carousel__slide").length>0&&new Carousel}document.addEventListener("DOMContentLoaded",()=>{initializeHeroCarousel();const e=document.getElementById("hero-scroll-hint");e&&e.addEventListener("click",()=>{const e=document.getElementById("about");e&&e.scrollIntoView({behavior:"smooth",block:"start"})})});class Carousel{constructor(){this.currentSlide=0,this.slides=document.querySelectorAll(".carousel__slide"),this.dots=document.querySelectorAll(".carousel__dot"),this.prevBtn=document.querySelector(".carousel__arrow--prev"),this.nextBtn=document.querySelector(".carousel__arrow--next"),this.autoPlayInterval=null,this.isPaused=!1,this.slides.length&&this.init()}init(){this.setupEventListeners(),this.setupKeyboardSupport(),this.setupHoverBehavior(),this.initTouchSupport(),this.startAutoPlay()}setupEventListeners(){this.dots.forEach((e,t)=>{e.addEventListener("click",()=>this.goToSlide(t))}),this.prevBtn&&this.prevBtn.addEventListener("click",()=>this.prevSlide()),this.nextBtn&&this.nextBtn.addEventListener("click",()=>this.nextSlide())}setupKeyboardSupport(){document.addEventListener("keydown",e=>{const t=document.activeElement;t&&("INPUT"===t.tagName||"TEXTAREA"===t.tagName||t.isContentEditable)||("ArrowLeft"===e.key&&this.prevSlide(),"ArrowRight"===e.key&&this.nextSlide())})}setupHoverBehavior(){const e=document.querySelector(".carousel");e&&(e.addEventListener("mouseenter",()=>this.pause()),e.addEventListener("mouseleave",()=>this.resume()))}goToSlide(e){this.slides[this.currentSlide].classList.remove("active"),this.dots[this.currentSlide].classList.remove("active"),this.currentSlide=e;const t=this.slides[this.currentSlide];t.classList.add("active"),this.dots[this.currentSlide].classList.add("active");const s=Array.from(t.querySelectorAll(".carousel__img-wrap, .carousel__badge, .carousel__title, .carousel__subtitle, .carousel__description, .carousel__actions"));s.forEach(e=>{e.style.animation="none"}),t.offsetWidth,s.forEach(e=>{e.style.animation=""})}nextSlide(){const e=(this.currentSlide+1)%this.slides.length;this.goToSlide(e)}prevSlide(){const e=(this.currentSlide-1+this.slides.length)%this.slides.length;this.goToSlide(e)}startAutoPlay(){this.autoPlayInterval=setInterval(()=>{this.isPaused||this.nextSlide()},7500)}resume(){this.isPaused=!1}pause(){this.isPaused=!0}initTouchSupport(){const e=document.querySelector(".carousel__track");if(!e)return;let t=0,s=!1;e.addEventListener("touchstart",e=>{t=e.touches[0].clientX,s=!0},{passive:!0}),e.addEventListener("touchend",e=>{if(!s)return;const i=t-e.changedTouches[0].clientX;Math.abs(i)>40&&(i>0?this.nextSlide():this.prevSlide()),s=!1},{passive:!0})}}